:root {
  --card-bg: #ffffff;
  --header-bg: #f0f4ff;
  --border-color: #e2e8f0;
  --category-color: #4f46e5;
  --progress-color: #64748b;
  --label-color: #94a3b8;
  --question-color: #1e293b;
  --correct-bg: #f0fdf4;
  --correct-border: #22c55e;
  --correct-letter-bg: #22c55e;
  --correct-letter-color: #ffffff;
  --correct-text-color: #15803d;
  --correct-icon-color: #22c55e;
  --wrong-bg: #fff5f5;
  --wrong-border: #ef4444;
  --wrong-letter-bg: #ef4444;
  --wrong-letter-color: #ffffff;
  --wrong-text-color: #b91c1c;
  --wrong-icon-color: #ef4444;
  --neutral-bg: #f8fafc;
  --neutral-border: #e2e8f0;
  --neutral-letter-bg: #e2e8f0;
  --neutral-letter-color: #475569;
  --neutral-text-color: #475569;
  --score-label-color: #94a3b8;
  --score-value-color: #1e293b;
  --btn-bg: #4f46e5;
  --btn-color: #ffffff;
  --btn-radius: 10px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.quiz-card {
  background: var(--card-bg);
  border: 1.5px solid var(--border-color);
  border-radius: 18px;
  width: 320px;
  overflow: hidden;
}

.quiz-header {
  background: var(--header-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 18px;
  border-bottom: 1.5px solid var(--border-color);
}

.quiz-category {
  font-size: 13px;
  font-weight: 700;
  color: var(--category-color);
}

.quiz-progress {
  font-size: 12px;
  font-weight: 600;
  color: var(--progress-color);
  background: var(--card-bg);
  border: 1.5px solid var(--border-color);
  border-radius: 20px;
  padding: 2px 10px;
}

.quiz-question {
  padding: 16px 18px 10px;
}

.question-label {
  font-size: 11px;
  font-weight: 600;
  color: var(--label-color);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  margin: 0 0 6px;
}

.question-text {
  font-size: 15px;
  font-weight: 700;
  color: var(--question-color);
  line-height: 1.45;
  margin: 0;
}

.answer-list {
  list-style: none;
  margin: 0;
  padding: 4px 18px 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.answer-item {
  display: flex;
  align-items: center;
  gap: 10px;
  border-radius: 10px;
  border: 1.5px solid var(--neutral-border);
  padding: 9px 12px;
  background: var(--neutral-bg);
}

.answer-correct {
  background: var(--correct-bg);
  border-color: var(--correct-border);
}

.answer-wrong {
  background: var(--wrong-bg);
  border-color: var(--wrong-border);
}

.answer-letter {
  width: 26px;
  height: 26px;
  border-radius: 7px;
  background: var(--neutral-letter-bg);
  color: var(--neutral-letter-color);
  font-size: 12px;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.answer-correct .answer-letter {
  background: var(--correct-letter-bg);
  color: var(--correct-letter-color);
}

.answer-wrong .answer-letter {
  background: var(--wrong-letter-bg);
  color: var(--wrong-letter-color);
}

.answer-text {
  font-size: 13px;
  font-weight: 600;
  color: var(--neutral-text-color);
  flex: 1;
}

.answer-correct .answer-text {
  color: var(--correct-text-color);
}

.answer-wrong .answer-text {
  color: var(--wrong-text-color);
}

.answer-icon {
  font-size: 14px;
  font-weight: 700;
  color: var(--correct-icon-color);
  width: 16px;
  text-align: center;
}

.answer-wrong .answer-icon {
  color: var(--wrong-icon-color);
}

.quiz-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 18px 16px;
  border-top: 1.5px solid var(--border-color);
}

.score-block {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.score-label {
  font-size: 11px;
  font-weight: 600;
  color: var(--score-label-color);
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

.score-value {
  font-size: 17px;
  font-weight: 800;
  color: var(--score-value-color);
}

.next-btn {
  background: var(--btn-bg);
  color: var(--btn-color);
  border: none;
  border-radius: var(--btn-radius);
  padding: 9px 16px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
}
